/**
 * CodeMirror 6 autocompletion for ArchLang, backed by the core's pure
 * `completion()` language service (the same engine the LSP/editor use).
 *
 * This file is hand-written (NOT generated) on purpose: `arch-language.js` is
 * regenerated by `scripts/gen-grammars.ts` and CI fails on drift, so the
 * completion wiring lives here instead, beside it.
 */
import { autocompletion } from "@codemirror/autocomplete";
import { completion as archComplete } from "archlang";

// Core CompletionKind → CodeMirror `type` (drives the icon/colour in the popup).
const KIND_TO_CM = {
  keyword: "keyword",
  element: "class",
  variable: "variable",
  function: "function",
  component: "namespace",
  enum: "constant",
};

/**
 * A CodeMirror `autocompletion` extension whose single source asks the compiler
 * what identifiers are in scope at the cursor. ArchLang identifiers can contain
 * hyphens (`right-of`, `left-of`, `drawn_by`), so the matched word includes `-`.
 */
export function archCompletion() {
  return autocompletion({
    override: [
      (ctx) => {
        const word = ctx.matchBefore(/[\w-]+/);
        if (!word && !ctx.explicit) return null;
        let items;
        try {
          items = archComplete(ctx.state.doc.toString(), ctx.pos);
        } catch {
          return null; // completion is advisory — never break typing on a parse hiccup
        }
        if (!items || items.length === 0) return null;
        return {
          from: word ? word.from : ctx.pos,
          options: items.map((i) => ({
            label: i.label,
            type: KIND_TO_CM[i.kind] ?? "text",
            detail: i.detail,
            info: i.doc,
          })),
          validFor: /^[\w-]*$/,
        };
      },
    ],
  });
}
